const fs = require('fs');
const profile = JSON.parse(fs.readFileSync('/data/user_profile.json', 'utf8'));
const ratingsHistory = JSON.parse(fs.readFileSync('/data/ratings_history.json', 'utf8'));
return [{json: {profile, ratingsHistory}}];

const profile = $input.first().json.profile;
// Build list of RSS URLs to fetch
const rssItems = profile.known_podcasts
  .filter(p => p.rss_url && p.priority >= 3)
  .map(p => ({name: p.name, url: p.rss_url, priority: p.priority}));
// Add websites
const websites = (profile.websites || []).filter(w => w.type === 'rss' && w.priority >= 4);
return [...rssItems, ...websites].map(item => ({json: item}));

// Filter episodes from last 7 days and format
const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
const items = $input.all();
const episodes = [];
for (const item of items) {
  const pub = new Date(item.json.pubDate || item.json.isoDate || 0);
  if (pub >= sevenDaysAgo) {
    const durationStr = item.json.itunes?.duration || '0';
    let durationMin = 0;
    if (durationStr.includes(':')) {
      const parts = durationStr.split(':').map(Number);
      durationMin = parts.length === 3 ? parts[0] * 60 + parts[1] : parts[0];
    } else {
      durationMin = Math.floor(parseInt(durationStr) / 60);
    }
    episodes.push({
      id: 'podcast_' + Buffer.from(item.json.link || item.json.title || '').toString('base64').slice(0, 12),
      type: 'podcast',
      title: item.json.title,
      description: item.json.contentSnippet || item.json.content || '',
      duration_minutes: durationMin,
      url: item.json.link,
      feed_name: item.json.feedUrl || '',
      published_at: item.json.pubDate
    });
  }
}
return episodes.map(e => ({json: e}));

// Listen Notes discovery
const profile = $('Read Profile').first().json.profile;
const interests = profile.interests || {};
const topTopics = Object.entries(interests)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([k]) => k.replace(/_/g, ' '));
return topTopics.map(term => ({json: {search_term: term}}));

const profile = $('Read Profile').first().json.profile;
const knownNames = new Set(profile.known_podcasts.map(p => p.name.toLowerCase()));
const allDiscovered = [];
// Process ListenNotes results
const lnItems = $('Discover ListenNotes').all();
for (const item of lnItems) {
  const results = item.json.results || [];
  for (const ep of results) {
    const podName = ep.podcast?.title_original || ep.podcast?.title || '';
    if (knownNames.has(podName.toLowerCase())) continue;
    allDiscovered.push({
      id: 'disc_ln_' + (ep.id || '').slice(0, 12),
      type: 'podcast',
      title: ep.title_original || ep.title || '',
      description: ep.description_original || ep.description || '',
      duration_minutes: Math.floor((ep.audio_length_sec || 0) / 60),
      url: ep.link || ep.audio || '',
      feed_name: podName,
      published_at: ep.pub_date_ms ? new Date(ep.pub_date_ms).toISOString() : null,
      is_discovery: true,
      source: 'listennotes'
    });
  }
}
// Process PodcastIndex results
const piItems = $('Discover PodcastIndex').all();
for (const item of piItems) {
  const feeds = item.json.feeds || [];
  for (const feed of feeds) {
    if (knownNames.has((feed.title || '').toLowerCase())) continue;
    allDiscovered.push({
      id: 'disc_pi_' + (feed.id || '').toString().slice(0, 12),
      type: 'podcast',
      title: feed.title || '',
      description: feed.description || '',
      duration_minutes: 45,
      url: feed.link || feed.url || '',
      feed_name: feed.title || '',
      published_at: feed.lastUpdateTime ? new Date(feed.lastUpdateTime * 1000).toISOString() : null,
      is_discovery: true,
      source: 'podcastindex'
    });
  }
}
// Deduplicate by normalized name
const seen = new Set();
const unique = allDiscovered.filter(item => {
  const key = item.feed_name.toLowerCase().trim();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});
return unique.map(item => ({json: item}));

// Format YouTube results
const items = $input.all();
const videos = [];
for (const item of items) {
  const results = item.json.items || [];
  for (const video of results) {
    videos.push({
      id: 'yt_' + (video.id?.videoId || ''),
      type: 'youtube',
      title: video.snippet?.title || '',
      description: video.snippet?.description || '',
      duration_minutes: 0,
      url: `https://www.youtube.com/watch?v=${video.id?.videoId}`,
      feed_name: video.snippet?.channelTitle || '',
      published_at: video.snippet?.publishedAt,
      is_discovery: false,
      thumbnail: video.snippet?.thumbnails?.medium?.url
    });
  }
}
return videos.map(v => ({json: v}));

// Assemble all content for Claude
const profile = $('Read Profile').first().json.profile;
const ratingsHistory = $('Read Profile').first().json.ratingsHistory;
const rssItems = $('Filter Last 7 Days').all().map(i => i.json);
const discoveryItems = $('Merge & Deduplicate Discoveries').all().map(i => i.json);
const youtubeItems = $('Format YouTube Results').all().map(i => i.json);
const allItems = [...rssItems, ...discoveryItems, ...youtubeItems];

// Build Claude payload
const inp = $input.first().json;
const claudePayload = {
  model: "claude-sonnet-4-5",
  max_tokens: 4096,
  system: "Eres un curador personal de contenidos. Filtra, punt\u00faa y resume episodios/v\u00eddeos seg\u00fan el perfil del usuario. Devuelve JSON v\u00e1lido con la estructura especificada. Sin texto adicional fuera del JSON.",
  messages: [{role: "user", content:
    "Perfil: " + JSON.stringify(inp.profile) +
    "\n\nContenido: " + JSON.stringify(inp.content_items) +
    "\n\nHistorial de ratings: " + JSON.stringify((inp.ratingsHistory && inp.ratingsHistory.ratings || []).slice(-20)) +
    "\n\nSemana: " + inp.week_number +
    "\n\nDevuelve JSON con estructura: {week_number, items: [{id, type, title, feed_name, duration_minutes, score, summary, why_relevant, tags}], total_found, total_selected}"
  }]
};

return [{
  json: {
    profile,
    ratingsHistory,
    content_items: allItems,
    week_number: Math.ceil((new Date() - new Date(new Date().getFullYear(), 0, 1)) / (7 * 24 * 60 * 60 * 1000))
  }
}];
// claudePayload available in output

const fs = require('fs');
const claudeResponse = $input.first().json;
const content = claudeResponse.content?.[0]?.text || '{}';
let digest;
try { digest = JSON.parse(content); } catch(e) {
  const match = content.match(/\{[\s\S]*\}/);
  digest = match ? JSON.parse(match[0]) : {week_number: 0, items: []};
}
digest.generated_at = new Date().toISOString();
fs.writeFileSync('/data/last_digest.json', JSON.stringify(digest, null, 2));
return [{json: digest}];

const digest = $input.first().json;
const items = digest.items || [];
const weekNum = digest.week_number || 0;

// Group by type
const knownPodcasts = items.filter(i => i.type === 'podcast' && !i.is_discovery);
const discoveries = items.filter(i => i.type === 'podcast' && i.is_discovery);
const youtubeItems = items.filter(i => i.type === 'youtube');
const articles = items.filter(i => i.type === 'article');

const telegramMessages = [];

function makeButtons(item) {
  const id = item.id.slice(0, 20);
  const type = item.type === 'youtube' ? 'youtube' : 'podcast';
  return {
    inline_keyboard: [[
      {text: '👍 Bien', callback_data: `like:${type}:${id}`},
      {text: '👎 No era para mí', callback_data: `dislike:${type}:${id}`},
      {text: '⭐ Puntuar', callback_data: `rate:${type}:${id}`},
      {text: '💬 Más info', callback_data: `info:${type}:${id}`}
    ]]
  };
}

let headerText = `📬 *Digest — semana ${weekNum}*\n`;

if (knownPodcasts.length > 0) {
  headerText += `\n🎙️ *PODCASTS CONOCIDOS* (${knownPodcasts.length})\n`;
  for (const item of knownPodcasts) {
    headerText += `• *${item.title}* — ${item.feed_name} · ${item.duration_minutes}min · ⭐${item.score}/10\n  _${item.summary}_\n  🔗 ${item.url}\n`;
  }
}

if (discoveries.length > 0) {
  headerText += `\n🔍 *DESCUBRIMIENTOS* (${discoveries.length})\n`;
  for (const item of discoveries) {
    headerText += `• *${item.title}* — _Nuevo: ${item.feed_name}_ · ${item.duration_minutes}min · ⭐${item.score}/10\n  _Por qué: ${item.recommendation_reason}_\n  🔗 ${item.url}\n`;
  }
}

if (youtubeItems.length > 0) {
  headerText += `\n📺 *YOUTUBE* (${youtubeItems.length})\n`;
  for (const item of youtubeItems) {
    headerText += `• *${item.title}* — ${item.feed_name} · ⭐${item.score}/10\n  🔗 ${item.url}\n`;
  }
}

if (articles.length > 0) {
  headerText += `\n🌐 *ARTÍCULOS* (${articles.length})\n`;
  for (const item of articles) {
    headerText += `• *${item.title}* — ${item.feed_name} · ⭐${item.score}/10\n`;
  }
}

headerText += `\n📅 *AGENDA*\n_Calculando sugerencias de calendario..._`;

// First message: full digest text
telegramMessages.push({
  text: headerText,
  reply_markup: null,
  is_header: true
});

// Individual item messages with buttons
for (const item of items) {
  telegramMessages.push({
    text: `_Feedback para: ${item.title.slice(0, 50)}_`,
    reply_markup: JSON.stringify(makeButtons(item)),
    item_id: item.id,
    is_header: false
  });
}

return telegramMessages.map(msg => ({json: msg}));
